"""Filters for narrowing down log entries."""
from __future__ import annotations

import re
from datetime import datetime
from typing import Callable

from .parser import LogEntry


def status_filter(status: str | int) -> Callable[[LogEntry], bool]:
    """Return a predicate that matches entries whose status equals the given code.

    `status` may come from the CLI as a string. Compare against int.
    """
    status_int = int(status)

    def pred(entry: LogEntry) -> bool:
        return entry.status == status_int

    return pred


def url_regex_filter(pattern: str) -> Callable[[LogEntry], bool]:
    """Return a predicate that matches entries whose URL matches the given regex."""
    rx = re.compile(pattern)

    def pred(entry: LogEntry) -> bool:
        return rx.search(entry.url) is not None

    return pred


def ip_allowlist_filter(allowlist) -> Callable[[LogEntry], bool]:
    """Match entries from any IP in the allowlist.

    `allowlist` should be iterable of IP strings.
    Converted to a set for O(1) lookup.
    """
    ip_set = set(allowlist)

    def pred(entry: LogEntry) -> bool:
        return entry.ip in ip_set

    return pred


def date_range_filter(
    since: datetime | None, until: datetime | None
) -> Callable[[LogEntry], bool]:
    """Match entries whose timestamp is within [since, until], either side optional."""

    def pred(entry: LogEntry) -> bool:
        if since is not None and entry.timestamp < since:
            return False
        if until is not None and entry.timestamp > until:
            return False
        return True

    return pred


def expression_filter(expr: str) -> Callable[[LogEntry], bool]:
    """Filter by a Python expression where `entry` is the LogEntry.

    Examples:
        "entry.status >= 500"
        "entry.bytes > 1024 and entry.method == 'GET'"

    Uses compile() with restricted globals for safety.
    """
    compiled = compile(expr, "<expr>", "eval")

    def pred(entry: LogEntry) -> bool:
        return bool(
            eval(
                compiled,
                {"__builtins__": {}},
                {"entry": entry},
            )
        )

    return pred


def combine_and(*preds):
    """Combine predicates with AND. Returns True iff all predicates do."""

    def pred(entry: LogEntry) -> bool:
        for p in preds:
            if not p(entry):
                return False
        return True

    return pred

"""Aggregations over log entries."""
from __future__ import annotations

from collections import Counter
from typing import Iterable

from .parser import LogEntry


def by_status(entries: Iterable[LogEntry]) -> Counter:
    """Count entries by HTTP status code."""
    c = Counter()
    for e in entries:
        c[e.status] += 1
    return c


def by_url(
    entries: Iterable[LogEntry], top: int | None = None
) -> list[tuple[str, int]]:
    """Count entries by URL, sorted descending. Optionally truncate to top N."""
    c = Counter(e.url for e in entries)
    items = c.most_common()
    if top is not None:
        items = items[:top]
    return items


def by_hour(entries: Iterable[LogEntry]) -> dict[int, int]:
    """Bucket entries by hour-of-day (0-23) based on their UTC timestamp."""
    buckets: dict[int, int] = {h: 0 for h in range(24)}
    for e in entries:
        # Use the datetime's hour directly since timestamps are stored in UTC
        hour = e.timestamp.hour
        buckets[hour] += 1
    return buckets


def total_bytes(entries: Iterable[LogEntry]) -> int:
    """Sum of bytes served across all entries."""
    return sum(e.bytes for e in entries)

"""Output formatters: JSON, CSV, plain text."""
from __future__ import annotations

import csv
import io
import json
from typing import Any, Iterable

from .parser import LogEntry


def to_json(entries: Iterable[LogEntry]) -> str:
    """Render entries as a JSON array."""
    data = [
        {
            "ip": e.ip,
            "user": e.user,
            "timestamp": e.timestamp.isoformat(),
            "method": e.method,
            "url": e.url,
            "protocol": e.protocol,
            "status": e.status,
            "bytes": e.bytes,
        }
        for e in entries
    ]
    return json.dumps(data)


def to_csv(entries: Iterable[LogEntry]) -> str:
    """Render entries as CSV (with header row)."""
    buf = io.StringIO()
    w = csv.writer(buf)
    w.writerow(
        ["ip", "user", "timestamp", "method", "url", "protocol", "status", "bytes"]
    )
    for e in entries:
        w.writerow(
            [
                e.ip,
                e.user,
                e.timestamp.isoformat(),
                e.method,
                e.url,
                e.protocol,
                e.status,
                e.bytes,
            ]
        )
    return buf.getvalue()


def to_text(entries: Iterable[LogEntry]) -> str:
    """Render entries as readable plain text, one entry per line."""
    lines = []
    for e in entries:
        lines.append(
            f"{e.timestamp.isoformat()}  {e.ip:>15}  {e.method:<6} {e.status} {e.url}"
        )
    return "\n".join(lines)


def render_aggregate(agg: Any, fmt: str = "text") -> str:
    """Render an aggregate result (Counter, dict, list) as text/json/csv."""
    if fmt == "text":
        if hasattr(agg, "items"):
            return "\n".join(f"{k}\t{v}" for k, v in agg.items())
        return "\n".join(f"{k}\t{v}" for k, v in agg)
    elif fmt == "json":
        if hasattr(agg, "items"):
            items = list(agg.items())
        else:
            items = list(agg)
        return json.dumps(dict(items))
    elif fmt == "csv":
        if hasattr(agg, "items"):
            items = list(agg.items())
        else:
            items = list(agg)
        buf = io.StringIO()
        w = csv.writer(buf)
        w.writerow(["key", "value"])
        for k, v in items:
            w.writerow([k, v])
        return buf.getvalue()
    else:
        raise ValueError(f"unknown format: {fmt}")

"""Miscellaneous utilities."""
from __future__ import annotations

from datetime import datetime, timezone


def parse_iso_date(s: str) -> datetime:
    """Parse a YYYY-MM-DD string into a UTC datetime at midnight."""
    return datetime.strptime(s, "%Y-%m-%d").replace(tzinfo=timezone.utc)

"""Command-line entry point."""
from __future__ import annotations

import argparse
import sys

from . import __version__
from .filters import (
    combine_and,
    date_range_filter,
    expression_filter,
    ip_allowlist_filter,
    status_filter,
    url_regex_filter,
)
from .aggregate import by_hour, by_status, by_url
from .io import load_iter
from .output import render_aggregate, to_csv, to_json, to_text
from .utils import parse_iso_date


def build_parser() -> argparse.ArgumentParser:
    p = argparse.ArgumentParser(
        prog="logalyzer", description="Web log analyzer"
    )
    p.add_argument(
        "--version", action="version", version=f"logalyzer {__version__}"
    )
    p.add_argument("paths", nargs="+", help="Log file path(s)")
    p.add_argument("--status", help="Filter by HTTP status code")
    p.add_argument("--url", help="Regex pattern to match URLs against")
    p.add_argument(
        "--ip", action="append", default=[],
        help="IP allowlist (repeatable)",
    )
    p.add_argument(
        "--since", type=parse_iso_date, default=None,
        help="Earliest date (YYYY-MM-DD)",
    )
    p.add_argument(
        "--until", type=parse_iso_date, default=None,
        help="Latest date (YYYY-MM-DD)",
    )
    p.add_argument("--expr", help="Custom Python expression filter")
    p.add_argument(
        "--aggregate", choices=["status", "url", "hour"],
        help="Aggregate output",
    )
    p.add_argument(
        "--top", type=int, default=None,
        help="Limit aggregate results to top N",
    )
    p.add_argument(
        "--format", choices=["text", "json", "csv"], default="text",
    )
    return p


def main(argv=None) -> int:
    args = build_parser().parse_args(argv)

    preds = []
    if args.status is not None:
        preds.append(status_filter(args.status))
    if args.url is not None:
        preds.append(url_regex_filter(args.url))
    if args.ip:
        preds.append(ip_allowlist_filter(args.ip))
    if args.since is not None or args.until is not None:
        preds.append(date_range_filter(args.since, args.until))
    if args.expr is not None:
        preds.append(expression_filter(args.expr))

    pred = combine_and(*preds) if preds else (lambda e: True)

    entries = []
    for path in args.paths:
        for e in load_iter(path):
            if pred(e):
                entries.append(e)

    if args.aggregate == "status":
        agg = by_status(entries)
    elif args.aggregate == "url":
        agg = by_url(entries, top=args.top)
    elif args.aggregate == "hour":
        agg = by_hour(entries)
    else:
        agg = None

    if agg is not None:
        fmt = args.format if args.format != "csv" else "text"
        print(render_aggregate(agg, fmt=fmt))
    else:
        if args.format == "json":
            print(to_json(entries))
        elif args.format == "csv":
            print(to_csv(entries))
        else:
            print(to_text(entries))

    return 0


if __name__ == "__main__":
    sys.exit(main())
